import { useState, useEffect, useMemo, useCallback } from 'react';
import ExportBar from '../components/ExportBar';
import LoadingState from '../components/LoadingState';
import { api, apiPost } from '../utils/api';
import usePageTitle from '../hooks/usePageTitle';
import s from './AuditLogPage.module.css';

/* ─── Empty fallback for when API is unavailable ─── */
const MOCK_ENTRIES = [];
const MOCK_ALERT_RULES = [];

const ACTION_TYPES = ['all', 'kill', 'promote', 'suppress', 'approve', 'trade', 'login', 'login_failed', 'settings', 'export', 'alert', 'reconciliation'];
const STATUS_TYPES = ['all', 'success', 'failed'];

const ACTION_COLORS = {
  kill: '#F85149',
  promote: '#3FB950',
  suppress: '#D29922',
  approve: '#58A6FF',
  trade: '#3FB950',
  login: '#58A6FF',
  login_failed: '#F85149',
  settings: '#D29922',
  export: '#BC8CFF',
  alert: '#D29922',
  reconciliation: '#58A6FF',
};

function StatusBadge({ status }) {
  const colors = { success: '#3FB950', completed: '#3FB950', approved: '#3FB950', failed: '#F85149', rejected: '#F85149', pending: '#D29922' };
  const c = colors[(status || '').toLowerCase()] || '#8B949E';
  return (
    <span className={s.statusBadge} style={{ background: c }}>
      {status || 'unknown'}
    </span>
  );
}

function StatCard({ label, value, color, icon }) {
  return (
    <div className={s.statCard}>
      <div className={s.statIcon} style={{ color, background: `${color}15` }}>{icon}</div>
      <div className={s.statContent}>
        <div className={s.statValue} style={{ color }}>{value}</div>
        <div className={s.statLabel}>{label}</div>
      </div>
    </div>
  );
}

export default function AuditLogPage() {
  usePageTitle('Audit Log');
  const [entries, setEntries] = useState([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filterAction, setFilterAction] = useState('all');
  const [filterStatus, setFilterStatus] = useState('all');
  const [filterUser, setFilterUser] = useState('');
  const [fromDate, setFromDate] = useState('');
  const [toDate, setToDate] = useState('');
  const [expandedRow, setExpandedRow] = useState(null);
  const [alertRules, setAlertRules] = useState(MOCK_ALERT_RULES);
  const [showAlertRules, setShowAlertRules] = useState(false);
  const [page, setPage] = useState(1);
  const pageSize = 25;

  const fetchData = useCallback(async () => {
    setLoading(true);
    setError(null);
    try {
      let data = [];
      const auditResult = await api('/audit/recent', { silent: true });
      if (auditResult && Array.isArray(auditResult) && auditResult.length > 0) {
        data = auditResult.map(e => ({
          timestamp: e.timestamp || e.requested_at || e.created_at || '',
          action: e.action || 'unknown',
          user: e.actor || e.user || e.requested_by || 'system',
          resource: e.resource || e.target || (e.strategy_name ? `Strategy: ${e.strategy_name}` : '--'),
          ip: e.ip || e.ip_address || '--',
          details: e.details || e.reason || '',
          status: e.status || 'success',
        }));
      } else {
        // Try fallback endpoint
        const controlResult = await api('/control/audit', { silent: true });
        if (controlResult && Array.isArray(controlResult) && controlResult.length > 0) {
          data = controlResult.map(e => ({
            timestamp: e.timestamp || e.requested_at || e.created_at || '',
            action: e.action || 'unknown',
            user: e.actor || e.user || e.requested_by || 'system',
            resource: e.resource || e.target || (e.strategy_name ? `Strategy: ${e.strategy_name}` : '--'),
            ip: e.ip || e.ip_address || '--',
            details: e.details || e.reason || '',
            status: e.status || 'success',
          }));
        } else {
          data = [];
          setError('Connecting to audit log...');
        }
      }
      setEntries(data);
    } catch (err) {
      setEntries([]);
      setError(err?.message || 'Connecting to audit log...');
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchData();
  }, [fetchData]);

  /* ─── Filtering ─── */
  const filtered = useMemo(() => {
    return entries.filter(entry => {
      if (filterAction !== 'all' && entry.action !== filterAction) return false;
      if (filterStatus !== 'all' && entry.status !== filterStatus) return false;
      if (filterUser && !entry.user.toLowerCase().includes(filterUser.toLowerCase())) return false;
      if (fromDate && entry.timestamp < fromDate) return false;
      if (toDate && entry.timestamp > toDate + ' 23:59:59') return false;
      return true;
    });
  }, [entries, filterAction, filterStatus, filterUser, fromDate, toDate]);

  /* ─── Pagination ─── */
  const totalPages = Math.max(1, Math.ceil(filtered.length / pageSize));
  const paginated = filtered.slice((page - 1) * pageSize, page * pageSize);

  /* ─── Stats ─── */
  const stats = useMemo(() => {
    const today = new Date().toISOString().slice(0, 10);
    const todayEntries = entries.filter(e => e.timestamp.startsWith(today));
    const failedCount = entries.filter(e => e.status === 'failed').length;
    const uniqueUsers = [...new Set(entries.map(e => e.user))].length;
    const userCounts = {};
    entries.forEach(e => { userCounts[e.user] = (userCounts[e.user] || 0) + 1; });
    const mostActive = Object.entries(userCounts).sort((a, b) => b[1] - a[1])[0];
    return {
      totalToday: todayEntries.length,
      failed: failedCount,
      uniqueUsers,
      mostActive: mostActive ? `${mostActive[0]} (${mostActive[1]})` : '--',
    };
  }, [entries]);

  /* ─── CSV export handler ─── */
  function handleExportCSV() {
    const headers = ['Timestamp', 'User', 'Action', 'Resource', 'IP Address', 'Status', 'Details'];
    const rows = filtered.map(e => [e.timestamp, e.user, e.action, e.resource, e.ip, e.status, `"${(e.details || '').replace(/"/g, '""')}"`]);
    const csv = [headers.join(','), ...rows.map(r => r.join(','))].join('\n');
    const blob = new Blob([csv], { type: 'text/csv' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `audit-log-${new Date().toISOString().slice(0, 10)}.csv`;
    a.click();
    URL.revokeObjectURL(url);
  }

  function handleToggleAlertRule(id) {
    setAlertRules(prev =>
      prev.map(rule => rule.id === id ? { ...rule, enabled: !rule.enabled } : rule)
    );
  }

  function clearFilters() {
    setFilterAction('all');
    setFilterStatus('all');
    setFilterUser('');
    setFromDate('');
    setToDate('');
    setPage(1);
  }

  const hasFilters = filterAction !== 'all' || filterStatus !== 'all' || filterUser || fromDate || toDate;

  return (
    <div className={s.page}>
      <div className={s.pageHeader}>
        <div>
          <h1 className={s.title}>Audit Log</h1>
          <p className={s.subtitle}>
            Complete record of all actions, approvals, and system events
          </p>
        </div>
        <div className={s.headerActions}>
          <button
            className={`${s.headerButton} ${showAlertRules ? s.headerButtonActive : ''}`}
            onClick={() => setShowAlertRules(!showAlertRules)}
          >
            Alert Rules
          </button>
          <button className={s.exportButton} onClick={handleExportCSV}>
            Export CSV
          </button>
        </div>
      </div>

      {error && (
        <div className={s.errorBanner}>
          {typeof error === 'string' ? error : 'An error occurred'}
        </div>
      )}

      {/* ─── Stats Cards ─── */}
      <div className={s.statsGrid}>
        <StatCard label="Events Today" value={stats.totalToday} color="#58A6FF" icon="E" />
        <StatCard label="Failed Actions" value={stats.failed} color="#F85149" icon="!" />
        <StatCard label="Unique Users" value={stats.uniqueUsers} color="#3FB950" icon="U" />
        <StatCard label="Most Active" value={stats.mostActive} color="#D29922" icon="A" />
      </div>

      {/* ─── Alert Rules Panel ─── */}
      {showAlertRules && (
        <div className={s.alertRulesPanel}>
          <div className={s.alertRulesHeader}>
            <h3 className={s.alertRulesTitle}>Alert Rules</h3>
            <span className={s.alertRulesSubtitle}>Configure alerts on specific audit events</span>
          </div>
          <table className={s.alertTable}>
            <thead>
              <tr className={s.alertTheadRow}>
                <th className={s.alertTh}>Rule</th>
                <th className={s.alertTh}>Event</th>
                <th className={s.alertTh}>Threshold</th>
                <th className={s.alertTh}>Window</th>
                <th className={s.alertTh}>Notify</th>
                <th className={s.alertTh} style={{ width: 80 }}>Enabled</th>
              </tr>
            </thead>
            <tbody>
              {alertRules.map(rule => (
                <tr key={rule.id} className={s.alertRow}>
                  <td className={s.alertTd}>{rule.name}</td>
                  <td className={s.alertTd}>
                    <span className={s.actionBadge} style={{
                      color: ACTION_COLORS[rule.event] || '#8B949E',
                      background: `${ACTION_COLORS[rule.event] || '#8B949E'}18`,
                    }}>
                      {rule.event}
                    </span>
                  </td>
                  <td className={s.alertTdMono}>{rule.threshold}x</td>
                  <td className={s.alertTdMono}>{rule.window}</td>
                  <td className={s.alertTd} style={{ color: '#8B949E', fontSize: 12 }}>{rule.notify}</td>
                  <td className={s.alertTd}>
                    <button
                      className={`${s.toggleButton} ${rule.enabled ? s.toggleOn : s.toggleOff}`}
                      onClick={() => handleToggleAlertRule(rule.id)}
                    >
                      {rule.enabled ? 'ON' : 'OFF'}
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}

      {/* ─── Filter Bar ─── */}
      <div className={s.filterBar}>
        <div className={s.filterGroup}>
          <label className={s.filterLabel}>User</label>
          <input
            type="text"
            placeholder="Filter by user..."
            value={filterUser}
            onChange={e => { setFilterUser(e.target.value); setPage(1); }}
            className={s.input}
          />
        </div>
        <div className={s.filterGroup}>
          <label className={s.filterLabel}>Action</label>
          <select
            value={filterAction}
            onChange={e => { setFilterAction(e.target.value); setPage(1); }}
            className={s.select}
          >
            {ACTION_TYPES.map(t => (
              <option key={t} value={t}>{t === 'all' ? 'All Actions' : t.replace('_', ' ')}</option>
            ))}
          </select>
        </div>
        <div className={s.filterGroup}>
          <label className={s.filterLabel}>Status</label>
          <select
            value={filterStatus}
            onChange={e => { setFilterStatus(e.target.value); setPage(1); }}
            className={s.select}
          >
            {STATUS_TYPES.map(t => (
              <option key={t} value={t}>{t === 'all' ? 'All Statuses' : t}</option>
            ))}
          </select>
        </div>
        <div className={s.filterGroup}>
          <label className={s.filterLabel}>From</label>
          <input
            type="date"
            value={fromDate}
            onChange={e => { setFromDate(e.target.value); setPage(1); }}
            className={s.input}
          />
        </div>
        <div className={s.filterGroup}>
          <label className={s.filterLabel}>To</label>
          <input
            type="date"
            value={toDate}
            onChange={e => { setToDate(e.target.value); setPage(1); }}
            className={s.input}
          />
        </div>
        {hasFilters && (
          <button className={s.clearButton} onClick={clearFilters}>
            Clear
          </button>
        )}
      </div>

      {/* ─── Export bar ─── */}
      <ExportBar data={filtered} filename="audit-log" />

      {/* ─── Log Table ─── */}
      <LoadingState loading={loading} error={null} empty={!entries || entries.length === 0} type="table" rows={10} cols={6} onRetry={fetchData}>
        <div className={s.tableCard}>
          <table className={s.table}>
            <thead>
              <tr className={s.theadRow}>
                <th className={s.th}>Timestamp</th>
                <th className={s.th}>User</th>
                <th className={s.th}>Action</th>
                <th className={s.th}>Resource</th>
                <th className={s.th}>IP Address</th>
                <th className={s.th}>Status</th>
              </tr>
            </thead>
            <tbody>
              {paginated.map((entry, idx) => {
                const rowKey = `${entry.timestamp}-${idx}`;
                const isExpanded = expandedRow === rowKey;
                return (
                  <tbody key={rowKey}>
                    <tr
                      className={`${s.tableRow} ${isExpanded ? s.tableRowExpanded : ''}`}
                      onClick={() => setExpandedRow(isExpanded ? null : rowKey)}
                    >
                      <td className={s.tdTimestamp}>{entry.timestamp}</td>
                      <td className={s.tdUser}>{entry.user}</td>
                      <td className={s.td}>
                        <span className={s.actionBadge} style={{
                          color: ACTION_COLORS[entry.action] || '#E6EDF3',
                          background: `${ACTION_COLORS[entry.action] || '#8B949E'}18`,
                        }}>
                          {entry.action.replace('_', ' ')}
                        </span>
                      </td>
                      <td className={s.tdResource}>{entry.resource}</td>
                      <td className={s.tdIp}>{entry.ip}</td>
                      <td className={s.td}><StatusBadge status={entry.status} /></td>
                    </tr>
                    {isExpanded && (
                      <tr className={s.detailRow}>
                        <td colSpan={6} className={s.detailCell}>
                          <div className={s.detailContent}>
                            <div className={s.detailLabel}>Details</div>
                            <div className={s.detailText}>{entry.details || 'No additional details available.'}</div>
                            <div className={s.detailMeta}>
                              <span>User: <strong>{entry.user}</strong></span>
                              <span>IP: <strong>{entry.ip}</strong></span>
                              <span>Time: <strong>{entry.timestamp}</strong></span>
                            </div>
                          </div>
                        </td>
                      </tr>
                    )}
                  </tbody>
                );
              })}
            </tbody>
          </table>
        </div>

        {filtered.length === 0 && !loading && (
          <div className={s.emptyState}>
            No audit entries match the current filters.
          </div>
        )}
      </LoadingState>

      {/* ─── Pagination ─── */}
      <div className={s.paginationBar}>
        <span className={s.paginationInfo}>
          Showing {filtered.length === 0 ? 0 : (page - 1) * pageSize + 1}
          -{Math.min(page * pageSize, filtered.length)} of {filtered.length} entries
        </span>
        <div className={s.paginationButtons}>
          <button
            className={s.pageNavButton}
            onClick={() => setPage(p => Math.max(1, p - 1))}
            disabled={page === 1}
          >
            Prev
          </button>
          {Array.from({ length: Math.min(totalPages, 7) }, (_, i) => {
            let pageNum;
            if (totalPages <= 7) {
              pageNum = i + 1;
            } else if (page <= 4) {
              pageNum = i + 1;
            } else if (page >= totalPages - 3) {
              pageNum = totalPages - 6 + i;
            } else {
              pageNum = page - 3 + i;
            }
            return (
              <button
                key={pageNum}
                className={`${s.pageButton} ${page === pageNum ? s.pageButtonActive : ''}`}
                onClick={() => setPage(pageNum)}
              >
                {pageNum}
              </button>
            );
          })}
          <button
            className={s.pageNavButton}
            onClick={() => setPage(p => Math.min(totalPages, p + 1))}
            disabled={page === totalPages}
          >
            Next
          </button>
        </div>
      </div>
    </div>
  );
}
